PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel : INT;
    HighAlarmSP : REAL;
    LowAlarmSP : REAL;
    Hysteresis : REAL;
END_VAR
VAR_OUTPUT
    LevelPct : REAL;
    HighAlarm : BOOL;
    LowAlarm : BOOL;
END_VAR
VAR
    HighAlarmState : BOOL := FALSE;
    LowAlarmState : BOOL := FALSE;
    HighAlarmSP_init : REAL := 85.0;
    LowAlarmSP_init : REAL := 15.0;
    Hysteresis_init : REAL := 2.0;
END_VAR

(* Инициализация параметров по умолчанию *)
IF HighAlarmSP = 0.0 AND HighAlarmSP_init = 85.0 THEN
    HighAlarmSP := HighAlarmSP_init;
END_IF;
IF LowAlarmSP = 0.0 AND LowAlarmSP_init = 15.0 THEN
    LowAlarmSP := LowAlarmSP_init;
END_IF;
IF Hysteresis = 0.0 AND Hysteresis_init = 2.0 THEN
    Hysteresis := Hysteresis_init;
END_IF;

(* Расчет уровня в процентах *)
LevelPct := INT_TO_REAL(RawLevel) / 276.48;

(* HighAlarm с гистерезисом *)
IF LevelPct >= HighAlarmSP THEN
    HighAlarmState := TRUE;
ELSIF LevelPct < (HighAlarmSP - Hysteresis) THEN
    HighAlarmState := FALSE;
END_IF;
HighAlarm := HighAlarmState;

(* LowAlarm с гистерезисом *)
IF LevelPct <= LowAlarmSP THEN
    LowAlarmState := TRUE;
ELSIF LevelPct > (LowAlarmSP + Hysteresis) THEN
    LowAlarmState := FALSE;
END_IF;
LowAlarm := LowAlarmState;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR

VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR

VAR
    Start_Rising : R_TRIG;
    Motor_Running : BOOL;
    Timer_StartDelta : TON;
END_VAR

(* Rising edge detection for Start_btn *)
Start_Rising(CLK := Start_btn);

(* Logic for Motor_Running *)
IF Stop_btn OR Overload THEN
    Motor_Running := FALSE;
ELSIF Start_Rising.Q AND NOT Stop_btn AND NOT Overload THEN
    Motor_Running := TRUE;
END_IF;

(* Timer logic *)
Timer_StartDelta(IN := Motor_Running AND NOT Timer_StartDelta.Q, PT := T#3s);

(* Output logic *)
Main_Contactor := Motor_Running;
Star_Contactor := Motor_Running AND NOT Timer_StartDelta.Q;
Delta_Contactor := Motor_Running AND Timer_StartDelta.Q;

(* Fault logic *)
Fault := Overload;

END_PROGRAM

TYPE ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT); END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR
VAR
    CurrentState : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

(* Logic Priority: EStop > State Transitions *)
IF EStop THEN
    CurrentState := ST_FAULT;
ELSIF CurrentState = ST_FAULT THEN
    IF NOT EStop THEN
        CurrentState := ST_IDLE;
    END_IF;
ELSE
    CASE CurrentState OF
        ST_IDLE:
            IF StartCmd AND NOT EStop THEN
                CurrentState := ST_RUNNING;
            END_IF;
        ST_RUNNING:
            IF SensorPresent AND SensorDefect THEN
                CurrentState := ST_REJECTING;
            END_IF;
        ST_REJECTING:
            IF RejectTimer.Q THEN
                CurrentState := ST_RUNNING;
            END_IF;
    END_CASE;
END_IF;

(* Timer Logic *)
RejectTimer(IN := (CurrentState = ST_RUNNING AND SensorPresent AND SensorDefect) OR (CurrentState = ST_REJECTING), PT := T#500ms);

(* Output Assignment *)
MotorRun := (CurrentState = ST_RUNNING);
RejectSolenoid := (CurrentState = ST_REJECTING);

END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
END_VAR

VAR_OUTPUT
    Output : REAL;
END_VAR

VAR
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
    Integral : REAL := 0.0;
    PreviousError : REAL := 0.0;
    Ts : REAL;
    Error : REAL;
    P_term : REAL;
    I_term : REAL;
    D_term : REAL;
END_VAR

Ts := CycleTime / T#1s;

IF NOT Enable THEN
    Output := 0.0;
    Integral := 0.0;
    PreviousError := 0.0;
ELSE
    Error := Setpoint - ProcessValue;
    P_term := Kp * Error;
    Integral := Integral + Error * Ts;
    I_term := Ki * Integral;

    IF Ts > 0.0 THEN
        D_term := Kd * (Error - PreviousError) / Ts;
    ELSE
        D_term := 0.0;
    END_IF;

    PreviousError := Error;
    Output := P_term + I_term + D_term;
    Output := LIMIT(0.0, Output, 100.0);
END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR

VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR

VAR
    LeadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        P1Run := (LeadPump = 1) AND NOT Pump1Fault;
        P2Run := (LeadPump = 2) AND NOT Pump2Fault;
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;

    (* Переключение ведущего насоса при аварии *)
    IF Pump1Fault AND LeadPump = 1 THEN
        LeadPump := 2;
    ELSIF Pump2Fault AND LeadPump = 2 THEN
        LeadPump := 1;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort : BOOL;
END_VAR
VAR_OUTPUT
    Valve1 : BOOL;
    Valve2 : BOOL;
    Valve3 : BOOL;
    SeqDone : BOOL;
    SeqActive : BOOL;
END_VAR
VAR
    Step : INT := 0;
    T1 : TON;
    T2 : TON;
    T3 : TON;
END_VAR

(* Abort priority: reset sequence immediately *)
IF Abort THEN
    Step := 0;
END_IF;

CASE Step OF
    0: (* Ожидание запуска *)
        Valve1 := FALSE;
        Valve2 := FALSE;
        Valve3 := FALSE;
        SeqDone := FALSE;
        SeqActive := FALSE;
        IF StartSeq AND NOT Abort THEN
            Step := 1;
        END_IF;

    1: (* Клапан 1, выдержка 2 сек *)
        Valve1 := TRUE;
        Valve2 := FALSE;
        Valve3 := FALSE;
        SeqActive := TRUE;
        SeqDone := FALSE;
        T1(IN := TRUE, PT := T#2s);
        IF T1.Q THEN
            Step := 2;
        END_IF;

    2: (* Клапан 2, выдержка 3 сек *)
        Valve1 := FALSE;
        Valve2 := TRUE;
        Valve3 := FALSE;
        SeqActive := TRUE;
        SeqDone := FALSE;
        T2(IN := TRUE, PT := T#3s);
        IF T2.Q THEN
            Step := 3;
        END_IF;

    3: (* Клапан 3, выдержка 1 сек *)
        Valve1 := FALSE;
        Valve2 := FALSE;
        Valve3 := TRUE;
        SeqActive := TRUE;
        SeqDone := FALSE;
        T3(IN := TRUE, PT := T#1s);
        IF T3.Q THEN
            Step := 4;
        END_IF;

    4: (* Завершение: все клапаны закрыты *)
        Valve1 := FALSE;
        Valve2 := FALSE;
        Valve3 := FALSE;
        SeqDone := TRUE;
        SeqActive := FALSE;
END_CASE;

END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR

VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL := FALSE;
END_VAR

VAR
    ResetTrig : R_TRIG;
END_VAR

(* Детектор переднего фронта кнопки сброса *)
ResetTrig(CLK := ResetPB);

(* Логика защёлки аварии *)
IF (NOT EStopOK OR NOT GuardClosed) THEN
    SafetyFault := TRUE;
ELSIF ResetTrig.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

(* Разрешение работы механизма *)
MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch : BOOL;
    BatchTarget : INT := 1000;
END_VAR

VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR

VAR
    SensorEdge : R_TRIG;
    BatchCounter : CTU;
END_VAR

(* Детектор переднего фронта датчика бутылки *)
SensorEdge(CLK := ProductSensor);

(* Счётчик партии: нарастающий, сброс по ResetBatch, уставка BatchTarget *)
BatchCounter(
    CU := SensorEdge.Q,
    R := ResetBatch,
    PV := BatchTarget
);

(* Назначение выходов счётчика партии *)
BatchCount := BatchCounter.CV;
BatchComplete := BatchCounter.Q;

(* Накопительный счётчик: инкремент на каждый фронт датчика *)
IF SensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;

END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR

VAR_OUTPUT
    Filtered : REAL;
END_VAR

VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT := 0;
    Count : INT := 0;
    Sum : REAL := 0.0;
    EffectiveSize : INT;
END_VAR

EffectiveSize := LIMIT(1, WindowSize, 10);

IF NOT Enable THEN
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    IF Count < EffectiveSize THEN
        Buffer[Head] := RawInput;
        Sum := Sum + RawInput;
        Count := Count + 1;
        Head := (Head + 1) MOD EffectiveSize;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
        Buffer[Head] := RawInput;
        Head := (Head + 1) MOD EffectiveSize;
    END_IF;

    IF Count > 0 THEN
        Filtered := Sum / INT_TO_REAL(Count);
    ELSE
        Filtered := 0.0;
    END_IF;
END_IF;
END_FUNCTION_BLOCK
